// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

func resolvedName(id string, resolved map[string]ResolvedEntity) string {
	if r, ok := resolved[id]; ok {
		return r.Name
	}
	if len(id) > 8 {
		return id[:8] + "..."
	}
	return id
}

func resolvedType(id string, resolved map[string]ResolvedEntity) string {
	if r, ok := resolved[id]; ok && r.EntityType != "" {
		return r.EntityType
	}
	return ""
}

func shortType(entityType string) string {
	parts := strings.Split(entityType, ".")
	if len(parts) > 0 {
		return parts[len(parts)-1]
	}
	return entityType
}

